#include <stdio.h>
#include <string.h>
#include <stdlib.h>

typedef struct {char ch; int cnt;} Item;
int cmpItem(const void *a, const void *b){return ((Item*)b)->cnt - ((Item*)a)->cnt;}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char s[100005]; scanf("%s", s);
        int freq[26]={0};
        for(int i=0;i<N;i++) freq[s[i]-'a']++;
        int maxc=0; for(int i=0;i<26;i++) if(freq[i]>maxc) maxc=freq[i];
        if(maxc > (N+2)/3){
            printf("NO\n");
            continue;
        }
        Item items[26]; int m=0;
        for(int i=0;i<26;i++) if(freq[i]){items[m].ch='a'+i; items[m].cnt=freq[i]; m++;}
        qsort(items, m, sizeof(Item), cmpItem);
        int *pos = (int*)malloc(N*sizeof(int));
        int idx=0;
        for(int start=0; start<3; ++start){
            for(int i=start; i<N; i+=3) pos[idx++] = i;
        }
        char ans[100005];
        idx=0; int p=0;
        for(int i=0;i<m;i++){
            for(int k=0;k<items[i].cnt;k++){
                ans[pos[p++]] = items[i].ch;
            }
        }
        ans[N]='\0';
        printf("YES\n%s\n", ans);
        free(pos);
    }
    return 0;
}

