import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            char[] s = fs.next().toCharArray();
            int[] freq = new int[26];
            for (char c : s) freq[c - 'a']++;
            int max = 0;
            for (int f : freq) if (f > max) max = f;
            if (max > (N + 2) / 3) {
                out.append("NO\n");
                continue;
            }
            List<int[]> list = new ArrayList<>(); // {cnt, ch}
            for (int i = 0; i < 26; i++) if (freq[i] > 0) list.add(new int[]{freq[i], i});
            list.sort((a, b) -> Integer.compare(b[0], a[0]));
            int[] pos = new int[N];
            int idx = 0;
            for (int start = 0; start < 3; start++)
                for (int i = start; i < N; i += 3) pos[idx++] = i;
            char[] ans = new char[N];
            int p = 0;
            for (int[] arr : list) {
                int cnt = arr[0];
                char ch = (char) ('a' + arr[1]);
                for (int k = 0; k < cnt; k++) ans[pos[p++]] = ch;
            }
            out.append("YES\n");
            out.append(new String(ans)).append('\n');
        }
        System.out.print(out.toString());
    }

    // Fast scanner for Java
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + c - '0'; c = readByte(); }
            return val * sign;
        }
        String next() throws IOException {
            int c;
            do { c = readByte(); } while (c <= ' ');
            StringBuilder sb = new StringBuilder();
            while (c > ' ') { sb.append((char) c); c = readByte(); }
            return sb.toString();
        }
    }
}

