const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let output = [];
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  const s = input[idx++];
  const freq = new Array(26).fill(0);
  for (let ch of s) freq[ch.charCodeAt(0) - 97]++;
  let maxc = 0;
  for (let f of freq) if (f > maxc) maxc = f;
  if (maxc > Math.floor((N + 2) / 3)) {
    output.push('NO');
    continue;
  }
  // collect characters with counts
  const items = [];
  for (let i = 0; i < 26; ++i) if (freq[i] > 0) items.push({ch: String.fromCharCode(97 + i), cnt: freq[i]});
  items.sort((a, b) => b.cnt - a.cnt);
  // position order
  const pos = [];
  for (let start = 0; start < 3; ++start) {
    for (let i = start; i < N; i += 3) pos.push(i);
  }
  const ansArr = new Array(N);
  let p = 0;
  for (const it of items) {
    for (let k = 0; k < it.cnt; ++k) {
      ansArr[pos[p++]] = it.ch;
    }
  }
  output.push('YES');
  output.push(ansArr.join(''));
}
